This JS gives 'Cannot read properties of undefined'. Why?

const user = users.find(u => u.id === id);
console.log(user.name);

`Array.find` returns `undefined` when nothing matches, so if no user has that `id`, `user` is `undefined` and reading `user.name` throws.

Guard it:

```js
const user = users.find(u => u.id === id);
if (!user) {
  console.log('No user with id', id);
} else {
  console.log(user.name);
}
```

Or concisely with optional chaining: `console.log(user?.name ?? 'unknown')`.

```python
import pytest
from mymodule import add


def test_add_positive():
    assert add(2, 3) == 5


def test_add_with_zero():
    assert add(0, 7) == 7


def test_add_negatives():
    assert add(-4, -6) == -10


@pytest.mark.parametrize("a,b,expected", [(1, 1, 2), (100, 200, 300), (-5, 5, 0)])
def test_add_param(a, b, expected):
    assert add(a, b) == expected
```

Swap `mymodule` for wherever `add` lives. The parametrized case keeps it easy to add more inputs.

```go
package main

import (
	"encoding/json"
	"log"
	"net/http"
)

func main() {
	http.HandleFunc("/health", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(map[string]string{"status": "ok"})
	})
	log.Println("listening on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

Run it with `go run main.go`, then `curl localhost:8080/health` returns `{"status":"ok"}`.
